func TestNewTestConfigForLoop(t *testing.T) {
	opts := TestLoopConfigOpts{
		Assignee:                "alice@example.com",
		ReviewMaxRetries:        7,
		NoProgressCooldown:      9 * time.Hour,
		MaxNoChangesBeforeClose: 5,
